<section class="py-5"><div class="container"><div class="row justify-content-center"><div class="col-lg-8"><div class="card shadow-sm border-0"><div class="card-body p-4 p-md-5"><div class="d-flex justify-content-between mb-4"><div><h1 class="h3">Estimate <?=e($estimate['estimate_number'])?></h1><p class="text-muted mb-0">Prepared for <?=e($estimate['display_name'])?></p></div><span class="badge text-bg-primary align-self-start"><?=e($estimate['status'])?></span></div><table class="table"><thead><tr><th>Description</th><th class="text-end">Qty</th><th class="text-end">Rate</th><th class="text-end">Total</th></tr></thead><tbody><?php foreach($items as $i):?><tr><td><?=e($i['description'])?></td><td class="text-end"><?=e($i['quantity'])?></td><td class="text-end"><?=money($i['unit_price'])?></td><td class="text-end"><?=money($i['line_total'])?></td></tr><?php endforeach?></tbody><tfoot><tr><th colspan="3" class="text-end">Total</th><th class="text-end"><?=money($estimate['total'])?></th></tr></tfoot></table><?php if($estimate['status']==='sent'||$estimate['status']==='draft'):?><div class="d-flex gap-2 justify-content-end"><form method="post" action="/estimate/<?=e($estimate['public_token'])?>/decline"><?=csrf_field()?><button class="btn btn-outline-secondary">Decline</button></form><form method="post" action="/estimate/<?=e($estimate['public_token'])?>/accept"><?=csrf_field()?><button class="btn btn-success">Accept Estimate</button></form></div><?php elseif($estimate['status']==='accepted'):?><div class="alert alert-success">This estimate has been accepted. We will contact you to schedule service.</div><?php endif?></div></div></div></div></div></section>
<?php if(($estimate['status']??'')!=='accepted'): ?>
<section class="container pb-5"><div class="card"><div class="card-body"><h2 class="h5">Electronic acceptance and signature</h2><form method="post" action="/estimate/<?=e($estimate['public_token'])?>/sign" id="signatureForm"><?=csrf_field()?><div class="mb-3"><label class="form-label">Printed name</label><input class="form-control" name="signature_name" required></div><div class="mb-3"><label class="form-label">Signature</label><canvas id="signaturePad" class="border rounded w-100" height="180"></canvas><input type="hidden" name="signature_data" id="signatureData"></div><button type="button" class="btn btn-outline-secondary" id="clearSignature">Clear</button><button class="btn btn-success">Sign and accept</button></form></div></div></section>
<script>const c=document.getElementById('signaturePad'),x=c.getContext('2d');let d=false;function p(e){const r=c.getBoundingClientRect();return{x:(e.touches?e.touches[0].clientX:e.clientX)-r.left,y:(e.touches?e.touches[0].clientY:e.clientY)-r.top}}function s(e){d=true;const q=p(e);x.beginPath();x.moveTo(q.x,q.y);e.preventDefault()}function m(e){if(!d)return;const q=p(e);x.lineTo(q.x,q.y);x.lineWidth=2;x.lineCap='round';x.stroke();e.preventDefault()}function u(){d=false}['mousedown','touchstart'].forEach(v=>c.addEventListener(v,s));['mousemove','touchmove'].forEach(v=>c.addEventListener(v,m));['mouseup','mouseleave','touchend'].forEach(v=>c.addEventListener(v,u));document.getElementById('clearSignature').onclick=()=>x.clearRect(0,0,c.width,c.height);document.getElementById('signatureForm').addEventListener('submit',()=>document.getElementById('signatureData').value=c.toDataURL('image/png'));</script>
<?php endif; ?>
